function Get-EmbeddedMergedCards {
    $base64 = $EmbeddedMergedCardsGzipBase64 -replace '\s', ''
    $compressedBytes = [Convert]::FromBase64String($base64)
    $inputStream = [System.IO.MemoryStream]::new($compressedBytes)
    $gzipStream = [System.IO.Compression.GzipStream]::new(
        $inputStream,
        [System.IO.Compression.CompressionMode]::Decompress)
    $reader = [System.IO.StreamReader]::new(
        $gzipStream,
        [System.Text.Encoding]::UTF8)

    try {
        $json = $reader.ReadToEnd()
    }
    finally {
        $reader.Dispose()
        $gzipStream.Dispose()
        $inputStream.Dispose()
    }

    $parsed = $json | ConvertFrom-Json
    return @(foreach ($record in $parsed) { $record })
}

try {
    $records = @(Get-EmbeddedMergedCards)
    [Console]::Error.WriteLine(
        "[Read-EmbeddedMergedCards] Reading $($records.Count) embedded record(s).")

    foreach ($record in $records) {
        if ($ProcessRecord) {
            & $ProcessRecord $record
        }
        else {
            # Default read behavior: write each complete merged record.
            $record
        }
    }
}
catch {
    [Console]::Error.WriteLine(
        "[Read-EmbeddedMergedCards] Failed: $($_.Exception.Message)")
    throw
}
